import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum ProductsTypes {
  REQUEST = '@products/REQUEST',
  SUCCESS = '@products/SUCCESS',
  FAILED = '@products/FAILED',
  CLEAR = '@products/CLEAR',
}

export enum BlockTypes {
  XS = 'XS',
  VA = 'VA',
  VW = 'VW',
  SFF = 'SFF',
  SSR = 'SSR',
  VX = 'VX',
  XW = 'XW',
  T = 'T',
}

export enum FiservBlockTypes {
  WAITING_PAYMENT = 'W',
}

export type productsCallback = (data: {
  statusCode: number | undefined;
  response: ProductsResponseData | undefined;
}) => void;

export interface ProductCard {
  NomePortador: string;
  Produto: string;
  SubProduto: string;
  NomeEmbosso: string;
  NrCartao: string;
  Chave: string;
  DataVencimento: string;
  Titular: boolean;
  Bloqueio: boolean;
  TipoBloqueio: BlockTypes;
  UltimoBloqueio: string;
  LimiteDisponivel: number;
  SaldoAberto: number;
  TransacoesPendentes: number;
  Validade: string;
  MotivoCancelamento: string;
  Status?: string;
  Virtual: boolean;
  DataAberturaCartao: string;
  Limite: number;
  LimiteDisponivelCartao: number;
  Embossado: boolean;
  DataAtivacao: string;
}

export interface ProductsResponseData {
  data: {
    CartaoCredito: {
      Conta: string;
      Fatura: {
        EnderecoFatura: {
          Bairro: string;
          Cep: string;
          Cidade: string;
          Estado: string;
          Complemento: string;
          Logradouro: string;
          Numero: string;
        };
        FormaEnvio: string;
      };
      Logo?: number;
      DiasAtraso: number;
      DiaVencimento: string;
      MelhorDiaCompra: string;
      DataFechamento: string;
      Bloqueio: boolean;
      TipoBloqueio: FiservBlockTypes;
      UltimoBloqueio: string;
      Limite: number;
      LimiteDisponivel: number;
      LimiteSaque: number;
      SaldoAberto: number;
      SaldoAnterior: number;
      TransacoesPendentes: number;
      ComprasFaturar: number;
      ParceladoPendente: number;
      MotivoCancelamento: string;
      OfertaParcelamento: boolean;
      Oferta: never[];
      Cartoes: ProductCard[];
      CartaoVirtual: {
        NomePortador: string;
        NumeroCartao: string;
        Validade: string;
        Chave: string;
        ValidadeCvv: string;
        HoraValidadeCvv: string;
      };
    }[];
  };
}

export type ProductsReducerData = ProductsResponseData['data']['CartaoCredito'];

export interface ProductsReducerProps {
  isLoading: boolean;
  isError: boolean;
  isLoadingFromHome: boolean;
  data: ProductsReducerData;
  unlockCard: {
    isVisible: boolean;
    message: string;
    cardNumber: string | undefined;
  };
}

export type State = ProductsReducerProps;

export const initialState: ProductsReducerProps = {
  isLoading: false,
  isError: false,
  isLoadingFromHome: false,
  data: [],
  unlockCard: {
    isVisible: false,
    message: '',
  },
};

const productsReducer = createReducer(initialState, {
  [ProductsTypes.REQUEST](
    state: State,
    { isFromHome }: { isFromHome: boolean },
  ): State {
    return {
      ...state,
      isLoading: !isFromHome ? true : state.isLoading,
      isLoadingFromHome: isFromHome ? true : state.isLoading,
      isError: false,
    };
  },
  [ProductsTypes.SUCCESS](
    state: State,
    {
      data: { response, unlockCard },
    }: {
      data: {
        response: ProductsReducerData;
        unlockCard: ProductsReducerProps['unlockCard'];
      };
    },
  ): State {
    return {
      ...state,
      isLoading: false,
      isLoadingFromHome: false,
      isError: false,
      data: response,
      unlockCard,
    };
  },

  [ProductsTypes.FAILED](state: State): State {
    return {
      ...state,
      isLoading: false,
      isLoadingFromHome: false,
      isError: true,
    };
  },
  [ProductsTypes.CLEAR](): State {
    return initialState;
  },
});

interface ProductsActions {
  productRequest: (isFromHome?: boolean, callback?: productsCallback) => Action;
  productSuccess: (data: {
    response: ProductsReducerData;
    unlockCard: ProductsReducerProps['unlockCard'];
  }) => Action;
  productError: () => Action;
  productClean: () => Action;
}

export const productsAction: ProductsActions = {
  productRequest: (isFromHome?: boolean, callback?: productsCallback) => ({
    type: ProductsTypes.REQUEST,
    isFromHome,
    callback,
  }),
  productSuccess: (data: { response: ProductsReducerData }) => ({
    type: ProductsTypes.SUCCESS,
    data,
  }),
  productError: () => ({
    type: ProductsTypes.FAILED,
  }),
  productClean: () => ({
    type: ProductsTypes.CLEAR,
  }),
};

export default productsReducer;

