import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

type HomeInvoiceStatusTypes =
  | 'open'
  | 'paid'
  | 'default'
  | 'delayed'
  | 'closed'
  | 'late'
  | 'paidMessage'
  | 'unidentifiedPayment'
  | 'debitPayment';

export enum HomeInvoicesTypes {
  REQUEST_HOME_INVOICES = '@homeInvoices/REQUEST_HOME_INVOICES',
  SUCCESS_HOME_INVOICES = '@homeInvoices/SUCCESS_HOME_INVOICES',
  FAILED_HOME_INVOICES = '@homeInvoices/FAILED_HOME_INVOICES',
  CLEAN_HOME_INVOICES = '@homeInvoices/CLEAN_HOME_INVOICES',
}

type HomeInvoiceSituation = 'closed' | 'Fechada' | 'Em Aberto';

type HomeInvoicePayment = 'Pago Integral' | 'Não Pago' | 'Pago Parcial';

export interface HomeInvoicesResponse {
  data: {
    invoices: HomeInvoiceFintechItem[];
  };
}

export interface HomeInvoiceFintechItem {
  Fechamento: string;
  Vencimento: string;
  Valor: number;
  ValorPago: number;
  Situacao: HomeInvoiceSituation | HomeInvoiceStatusTypes;
  Pagamento: HomeInvoicePayment;
  ValorPgtoMinimo: number;
  VencimentoOriginal: string;
  MelhorDiaCompra?: string;
  DataDeCorte?: string;
  ParcelamentoDisponivel?: boolean;
}

export interface HomeInvoicesProps {
  isLoading: boolean;
  isError: boolean;
  data: HomeInvoiceFintechItem[];
}

type State = HomeInvoicesProps;

const initialState: HomeInvoicesProps = {
  isLoading: false,
  isError: false,
  data: [],
};

const homeInvoicesReducer = createReducer(initialState, {
  [HomeInvoicesTypes.REQUEST_HOME_INVOICES](state: State): State {
    return {
      ...state,
      isLoading: true,
      isError: false,
    };
  },
  [HomeInvoicesTypes.SUCCESS_HOME_INVOICES](
    state: State,
    {
