import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum SimulationTypes {
  REQUEST = '@simulation/SIMULATION_REQUEST',
  SUCCESS = '@simulation/SIMULATION_SUCCESS',
  FAILED = '@simulation/SIMULATION_FAILED',
  CLEAR = '@simulation/SIMULATION_CLEAR',
}

type SimulationCallback = (data: {
  statusCode: number | undefined;
}) => void;

export interface SimulationOptions {
  Opcao: string;
  QuantidadeParcelas: string;
  ValorParcela: string;
  Taxas: string;
  ValorJuros: string;
  IofAdicional: string;
  IofDiario: string;
  CetMes: string;
  CetAno: string;
}

export interface SimulationResponse {
  code: number;
  message: string;
  data: {
    Cliente: string;
    Produto: string;
    SubProduto: string;
    TipoParcelado: string;
    Status: string;
    BillingCode: string;
    ContratosAbertos: string;
    SaldoFatura: string;
    Vencimento: string;
    DiasAtraso: string;
    ValorMinimo: string;
    ValorParcelado: string;
    TotalTransacao: string;
    ValorAdesao: string;
    Parcelas: string;
    UtilizaCred: string;
    TaxaAnual: string;
    Iof: 0.38;
    IofDiario: 0.0082;
    ListaParcelamentoOpcao: SimulationOptions[];
  };
}

export interface SimulationReducerProps {
  isLoading: boolean;
  isError: boolean;
  data: SimulationResponse['data'] | undefined;
}

type State = SimulationReducerProps;

const initialState: SimulationReducerProps = {
  isLoading: false,
  isError: false,
  data: undefined,
};

const simulationReducer = createReducer(initialState, {
  [SimulationTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [SimulationTypes.SUCCESS](
    state: State,
    { data }: { data: SimulationResponse['data'] },
  ): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      data,
    };
  },
  [SimulationTypes.FAILED](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [SimulationTypes.CLEAR](): State {
    return initialState;
  },
});

type SimulationActions = {
  simulationRequest: (callback: SimulationCallback) => Action;
  simulationSuccess: (data: SimulationResponse['data']) => Action;
  simulationFailed: () => Action;
  simulationClear: () => Action;
};

export const simulationActions: SimulationActions = {
  simulationRequest: callback => ({
    type: SimulationTypes.REQUEST,
    callback,
  }),
  simulationSuccess: data => ({
    type: SimulationTypes.SUCCESS,
    data,
  }),
  simulationFailed: () => ({
    type: SimulationTypes.FAILED,
  }),
  simulationClear: () => ({
    type: SimulationTypes.CLEAR,
  }),
};

export default simulationReducer;

