  CLEAR = '@unlockCard/UNLOCK_CARD_CLEAR',
}

export type UnlockCardCallback = (data: {
  statusCode: number | undefined;
}) => void;

export interface UnlockCardProps {
  isLoading: boolean;
  isError: boolean;
  isSuccessful: boolean;
}

type State = UnlockCardProps;

const initialState: UnlockCardProps = {
  isLoading: false,
  isError: false,
  isSuccessful: false,
};

const unlockCardReducer = createReducer(initialState, {
  [UnlockCardTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [UnlockCardTypes.SUCCESS](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
    };
  },
  [UnlockCardTypes.FAILED](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [UnlockCardTypes.CLEAR](): State {
    return initialState;
  },
});

type UnlockCardActions = {
  unlockCardRequest: (
    data: {
      lastFourNumbers: string;
    },
    callback: UnlockCardCallback,
  ) => Action;
  unlockCardSuccess: () => Action;
  unlockCardFailed: () => Action;
  unlockCardClear: () => Action;
  virtual?: boolean;
};

export const unlockCardActions: UnlockCardActions = {
  unlockCardRequest: (data, callback) => ({
