    type: UnlockCardTypes.SUCCESS,
  }),
  unlockCardFailed: () => ({
    type: UnlockCardTypes.FAILED,
  }),
  unlockCardClear: () => ({
    type: UnlockCardTypes.CLEAR,
  }),
};

export default unlockCardReducer;

