import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum UpdateLimitTypes {
  UPDATE_LIMIT_REQUEST = '@updateLimit/REQUEST_UPDATE_LIMIT',
  UPDATE_LIMIT_SUCCESS = '@updateLimit/UPDATE_LIMIT_SUCCESS',
  UPDATE_LIMIT_ERROR = '@updateLimit/UPDATE_LIMIT_ERROR',
  UPDATE_LIMIT_CLEAR = '@updateLimit/UPDATE_LIMIT_CLEAR',
}

interface UpdateLimitResponse {
  code: number;
  message: string;
  data: {
    message: string;
  };
}
interface UpdateLimitRequest {
  accountNumber: string;
  limit: number;
  encryptedCardNumber: string;
}

export interface UpdateLimitProps {
  isLoading: boolean;
  isError: boolean;
  isSuccess: boolean;
}

type State = UpdateLimitProps;

const initialState: UpdateLimitProps = {
  isError: false,
  isLoading: false,
  isSuccess: false,
};

const updateLimitReducer = createReducer(initialState, {
  [UpdateLimitTypes.UPDATE_LIMIT_REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
      isError: false,
      isSuccess: false,
    };
  },
  [UpdateLimitTypes.UPDATE_LIMIT_SUCCESS](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      isSuccess: true,
    };
  },
  [UpdateLimitTypes.UPDATE_LIMIT_ERROR](state: State): State {
    return {
      ...state,
      isError: true,
      isLoading: false,
      isSuccess: false,
    };
  },
  [UpdateLimitTypes.UPDATE_LIMIT_CLEAR](): State {
    return initialState;
  },
});

interface UpdateLimitActions {
  updateLimitRequest: ({
    lastFourNumbers,
    limit,
  }: {
    lastFourNumbers: string;
    limit: string;
  }) => Action;
  updateLimitSuccess: () => Action;
  updateLimitError: () => Action;
  updateLimitClear: () => Action;
}

export const updateLimitActions: UpdateLimitActions = {
  updateLimitRequest: ({ lastFourNumbers, limit }) => ({
    type: UpdateLimitTypes.UPDATE_LIMIT_REQUEST,
    limit,
    lastFourNumbers,
  }),
  updateLimitSuccess: () => ({
    type: UpdateLimitTypes.UPDATE_LIMIT_SUCCESS,
  }),
  updateLimitError: () => ({
    type: UpdateLimitTypes.UPDATE_LIMIT_ERROR,
  }),
  updateLimitClear: () => ({
    type: UpdateLimitTypes.UPDATE_LIMIT_CLEAR,
  }),
};

export default updateLimitReducer;

