import createReducer from '~/redux/store/createReducer';
import { Action } from 'redux';

export enum CredencialTypes {
  REQUEST = '@credencial/CREDENCIAL_REQUEST',
  SUCCESS = '@credencial/CREDENCIAL_SUCCESS',
  FAILED = '@credencial/CREDENCIAL_FAILED',
  CLEAR = '@credencial/CREDENCIAL_CLEAR',
}

export interface CredencialResponse {
  code: number;
  message: string;
  data: string;
}

export interface CredencialReducerProps {
  isLoading: boolean;
  isError: boolean;
  credencial: string | undefined;
}

type State = CredencialReducerProps;

const initialState: CredencialReducerProps = {
  isLoading: false,
  isError: false,
  credencial: undefined,
};

const credencialReducer = createReducer(initialState, {
  [CredencialTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [CredencialTypes.SUCCESS](
    state: State,
    { credencial }: { credencial: string },
  ): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      credencial,
    };
  },
  [CredencialTypes.FAILED](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [CredencialTypes.CLEAR](): State {
    return initialState;
  },
});

type CredencialActions = {
  credencialRequest: (lastFourNumbers: string) => Action;
  credencialSuccess: (credencial: string) => Action;
  credencialFailed: () => Action;
  credencialClear: () => Action;
};

export const credencialActions: CredencialActions = {
  credencialRequest: lastFourNumbers => ({
    type: CredencialTypes.REQUEST,
    lastFourNumbers,
  }),
  credencialSuccess: credencial => ({
    type: CredencialTypes.SUCCESS,
    credencial,
  }),
  credencialFailed: () => ({
    type: CredencialTypes.FAILED,
  }),
  credencialClear: () => ({
    type: CredencialTypes.CLEAR,
  }),
};

export default credencialReducer;

